	if p.isDocument {
		p.viewport.LineDown(1)
		return nil
	}
	if instance == nil || instance.Status == session.Paused {
		return nil
	}
	if !p.isScrolling {
		if err := p.enterScrollMode(instance); err != nil {
			return err
		}
		return nil
	}
	p.viewport.LineDown(1)
	return nil
}

